import { Agent, LocalAgentConfig } from '@google/antigravity';

async function runStreaming() {
  const config = new LocalAgentConfig();
  const agent = new Agent(config);
  await agent.start();

  try {
    const response = await agent.chat("Explain the difference between a list and a set in Python, including time complexity.");

    console.log("--- Agent Reasoning Thoughts ---");
    for await (const thought of response.thoughts) {
      process.stdout.write(thought);
    }
    console.log("\n");

    console.log("--- Agent Text Response ---");
    for await (const token of response) {
      process.stdout.write(token);
    }
    console.log("\n");
  } finally {
    await agent.stop();
  }
}

runStreaming().catch(console.error);

import { Agent, LocalAgentConfig } from '@google/antigravity';

async function runPromptStructuring() {
  const systemInstruction = 
    "You are a technical document editor. Your task is to clean up raw transcriptions. " +
    "Remove filler words, format command lines into markdown code blocks, and maintain a professional tone.";

  const config = new LocalAgentConfig({ systemInstruction });
  const agent = new Agent(config);
  await agent.start();

  const rawInput = "uh, so first you run python setup.py install and then, like, you execute agy --verify, you know?";

  const prompt = 
    "Please rewrite the following transcription matching your instructions:\n\n" +
    `<transcription>\n${rawInput}\n</transcription>\n\n` +
    "Output only the cleaned-up markdown formatting.";

  try {
    const response = await agent.chat(prompt);
    console.log(await response.text());
  } finally {
    await agent.stop();
  }
}

runPromptStructuring().catch(console.error);
